const contentIdeaId = Number($json.body?.contentIdeaId || $json.contentIdeaId || 0);
const workflowRunId = Number($json.body?.workflowRunId || $json.workflowRunId || 0);

if (!contentIdeaId || contentIdeaId <= 0) {
  throw new Error('contentIdeaId invalide ou manquant: ' + contentIdeaId);
}
if (!workflowRunId || workflowRunId <= 0) {
  throw new Error('workflowRunId invalide ou manquant: ' + workflowRunId);
}

return [{ json: { contentIdeaId, workflowRunId } }];

const idea = $json.body || $json;
if (!idea || !idea.id) throw new Error('contentIdea introuvable ou invalide');
if (idea.id !== Number($('Validate Input').item.json.contentIdeaId)) {
  throw new Error('Mismatch: contentIdeaId does not match');
}
if (!idea.shotstack_render_id) throw new Error('Aucun shotstack_render_id pour cette contentIdea');

const status = String(idea.shotstack_status || '').toLowerCase();
const validStatuses = ['queued', 'rendering', 'preparing', 'done', 'failed', 'timeout'];
if (!validStatuses.includes(status)) {
  throw new Error('Invalid shotstack_status: ' + status);
}

if (!['queued', 'rendering', 'preparing'].includes(status)) {
  return [{ json: { skip: true, reason: 'shotstack_status=' + status + ' — rien a faire', idea } }];
}

return [{ json: { skip: false, renderId: idea.shotstack_render_id, ideaId: idea.id, ideaStatus: idea.pipeline_status, idea } }];

const statusData = $json.body || $json;
if (!statusData || !statusData.response) throw new Error('Invalid Shotstack response');

const status = String(statusData.response?.status || '').toLowerCase();
const ideaId = $('Validate Render State').item.json.ideaId;
const validStatuses = ['queued', 'rendering', 'preparing', 'done', 'failed', 'timeout'];

if (!validStatuses.includes(status)) {
  throw new Error('Invalid Shotstack status: ' + status);
}

if (status === 'done') {
  if (!statusData.response?.url) throw new Error('No video URL in completed Shotstack response');
  return [{ json: {
    noUpdate: false,
    ideaId,
    patch: {
      shotstack_status: 'done',
      shotstack_url: statusData.response.url,
      final_video_status: 'ready',
      pipeline_status: 'render_ready'
    },
    callbackStatus: 'SUCCEEDED',
    callbackMessage: 'Render Shotstack termine.'
  } }];
}

if (status === 'failed' || status === 'timeout') {
  return [{ json: {
    noUpdate: false,
    ideaId,
    patch: {
      shotstack_status: status,
      final_video_status: 'failed',
      pipeline_status: 'failed'
    },
    callbackStatus: 'FAILED',
    callbackMessage: 'Render Shotstack en echec (' + status + ').'
  } }];
}

return [{ json: {
  noUpdate: true,
  ideaId,
  shotstackStatus: status,
  message: 'Render Shotstack toujours en cours.'
} }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Validate Input').item.json.workflowRunId || 0);
const status = $json.callbackStatus;
const message = $json.callbackMessage;
const contentIdeaId = $json.ideaId;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  throw new Error('Missing config for callback');
}

const body = JSON.stringify({
  status: status,
  message: message,
  responsePayload: JSON.stringify({
    contentIdeaId: contentIdeaId,
    shotstackStatus: $json.patch?.shotstack_status
  })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve, reject) => {
  let attempts = 0;
  const maxAttempts = 3;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(err);
      }
    });

    req.setTimeout(20000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(new Error('Callback timeout'));
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Callback failed: ' + response.statusCode + ' ' + response.body);
}

return [{ json: { ok: true, callbackStatusCode: response.statusCode } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Validate Input').item.json.workflowRunId || 0);
const contentIdeaId = Number($('Validate Input').item.json.contentIdeaId || 0);
const error = $json;

let errorMessage = 'Unknown error';
if (typeof error === 'string') errorMessage = error;
else if (error.message) errorMessage = error.message;
else if (error.error?.message) errorMessage = error.error.message;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  return [{ json: { status: 'FAILED', message: 'Missing config for error callback' } }];
}

const body = JSON.stringify({
  status: 'FAILED',
  message: 'Shotstack check failed: ' + errorMessage.slice(0, 200),
  responsePayload: JSON.stringify({ contentIdeaId, error: errorMessage.slice(0, 500) })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve, reject) => {
  let attempts = 0;
  const maxAttempts = 2;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback failed: ' + err.message });
      }
    });

    req.setTimeout(15000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback timeout' });
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

return [{ json: { status: 'FAILED', message: 'Error callback sent (best effort)', statusCode: response.statusCode } }];
